     * {@link CpioConstants.FORMAT_OLD_ASCII}<br/>
     * 
     * @param format
     *            The format to set.
     */
    final void setFormat(final short format) {
        switch (format) {
        case FORMAT_NEW:
            this.headerSize = 110;
            break;
        case FORMAT_NEW_CRC:
            this.headerSize = 110;
            break;
        case FORMAT_OLD_ASCII:
            this.headerSize = 76;
            break;
        case FORMAT_OLD_BINARY:
            this.headerSize = 26;
            break;
        default:
            throw new IllegalArgumentException("Unknown header type");
        }
        this.fileFormat = format;
    }

